INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '1. Utiliza métodos y técnicas específicas para realizar procesos básicos de investigación en Ciencias Sociales, según su propósito.', ARRAY['1.1. Selecciona un problema de investigación de su contexto.', '1.2. Planifica procesos de investigación del problema seleccionado.', '1.3. Se esfuerza por presentar un informe de investigación que cumpla con características científicas.']),
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '2. Propone medidas de mitigación para reducir el impacto demográfico y ambiental en su contexto.', ARRAY['2.1. Explica las características de la vulnerabilidad geográfica de Guatemala.', '2.2. Infiere la situación demográfica de Guatemala y su incidencia en el entorno.', '2.3. Opina sobre los efectos e impacto de la actividad económica en el ambiente guatemalteco.']),
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '3. Analiza las distintas relaciones de poder que se establecen en el proceso de formación del Estado guatemalteco.', ARRAY['3.1. Determina el contexto histórico de Guatemala y Europa en el cual se concretó la invasión y conquista.', '3.2. Explica la continuidad de las relaciones de poder internas y externas, posteriores a la Independencia de Guatemala y Centroamérica.', '3.3. Investiga sobre la prolongación de las relaciones de poder internas y externas en el tiempo hasta mediados del Siglo XX.', '3.4. Se interesa por profundizar en los procesos de la historia reciente de Guatemala.']),
('Tercero Básico', 'Ciencias Sociales, Formación Ciudadana e Interculturalidad', '4. Participa activamente en la transformación de conflictos, en el marco de la realidad social, cultural y política de su entorno.', ARRAY['4.1. Relaciona los Acuerdos de Paz con el fortalecimiento de la democracia participativa en Guatemala.', '4.2. Deduce el impacto de la rendición de cuentas y la auditoría social en las instituciones del Estado.', '4.3. Argumenta la importancia de los valores para la construcción de la democracia, cultura de legalidad e interculturalidad.']);
